"""

from dataclasses import dataclass, field
from typing import Dict, List, Set
import uuid


@dataclass
class InventoryRecord:
    product_id: str
    available: int
    reserved: int = 0
    sold: int = 0


@dataclass
class Reservation:
    order_id: str
    product_id: str
    quantity: int
    status: str  # RESERVED / CONFIRMED / RELEASED


@dataclass
class Order:
    order_id: str
    request_id: str
    user_id: str
    product_id: str
    quantity: int
    amount: int
    status: str
    expire_at_tick: int


@dataclass
class Payment:
    order_id: str
    amount: int
    status: str  # INIT / SUCCESS / FAILED
    provider_txn_id: str = ""


@dataclass
class Event:
    event_id: str
    event_type: str
    payload: dict


class EventBus:
    def __init__(self):
        self.queue: List[Event] = []
        self.processed: Dict[str, Set[str]] = {}
        self.handlers: Dict[str, List] = {}

    def subscribe(self, event_type: str, handler_name: str, func):
        self.handlers.setdefault(event_type, []).append((handler_name, func))
        self.processed.setdefault(handler_name, set())

    def publish(self, event_type: str, payload: dict, event_id: str = None):
        self.queue.append(Event(event_id or str(uuid.uuid4()), event_type, payload))

    def drain(self):
        while self.queue:
            event = self.queue.pop(0)
            for handler_name, func in self.handlers.get(event.event_type, []):
                if event.event_id in self.processed[handler_name]:
                    continue
                func(event)
                self.processed[handler_name].add(event.event_id)


class InventoryService:
    def __init__(self):
        self.inventory: Dict[str, InventoryRecord] = {}
        self.reservations: Dict[str, Reservation] = {}

    def add_product(self, product_id: str, stock: int):
        self.inventory[product_id] = InventoryRecord(product_id, stock)

    def reserve(self, order_id: str, product_id: str, quantity: int) -> bool:
        existing = self.reservations.get(order_id)
        if existing:
            return existing.status == "RESERVED"

        record = self.inventory[product_id]
        if record.available < quantity:
            return False

        record.available -= quantity
        record.reserved += quantity
        self.reservations[order_id] = Reservation(order_id, product_id, quantity, "RESERVED")
        return True

    def confirm(self, order_id: str):
        reservation = self.reservations.get(order_id)
        if not reservation or reservation.status == "CONFIRMED":
            return
        if reservation.status == "RELEASED":
            raise ValueError("cannot confirm released reservation")

        record = self.inventory[reservation.product_id]
        record.reserved -= reservation.quantity
        record.sold += reservation.quantity
        reservation.status = "CONFIRMED"

    def release(self, order_id: str):
        reservation = self.reservations.get(order_id)
        if not reservation or reservation.status in {"RELEASED", "CONFIRMED"}:
            return

        record = self.inventory[reservation.product_id]
        record.reserved -= reservation.quantity
        record.available += reservation.quantity
        reservation.status = "RELEASED"

    def snapshot(self):
        return {
            pid: {
                "available": rec.available,
                "reserved": rec.reserved,
                "sold": rec.sold,
            }
            for pid, rec in self.inventory.items()
        }


class OrderService:
    def __init__(self, inventory: InventoryService, bus: EventBus):
        self.inventory = inventory
        self.bus = bus
        self.orders: Dict[str, Order] = {}
        self.idempotency: Dict[str, dict] = {}
        self.tick = 0

    def create_order(self, request_id: str, user_id: str, product_id: str, quantity: int, amount: int):
        if request_id in self.idempotency:
            return self.idempotency[request_id]

        order_id = str(uuid.uuid4())
        order = Order(
            order_id=order_id,
            request_id=request_id,
            user_id=user_id,
            product_id=product_id,
            quantity=quantity,
            amount=amount,
            status="PENDING_RESERVATION",
            expire_at_tick=self.tick + 3,
        )
        self.orders[order_id] = order

        reserved = self.inventory.reserve(order_id, product_id, quantity)
        if not reserved:
            order.status = "REJECTED"
            response = {"order_id": order_id, "status": order.status}
            self.idempotency[request_id] = response
            return response

        order.status = "PENDING_PAYMENT"
        self.bus.publish("OrderCreated", {"order_id": order_id, "amount": amount})
        response = {"order_id": order_id, "status": order.status}
        self.idempotency[request_id] = response
        return response

    def mark_paid(self, order_id: str):
        order = self.orders[order_id]
        if order.status == "PAID":
            return
        if order.status not in {"PENDING_PAYMENT"}:
            return
        order.status = "PAID"
        self.bus.publish("OrderPaid", {"order_id": order_id})

    def mark_payment_failed(self, order_id: str):
        order = self.orders[order_id]
        if order.status != "PENDING_PAYMENT":
            return
        order.status = "PAYMENT_FAILED"
        self.bus.publish("OrderCancelled", {"order_id": order_id, "reason": "payment_failed"})

    def cancel_expired(self):
        for order in self.orders.values():
            if order.status == "PENDING_PAYMENT" and self.tick >= order.expire_at_tick:
                order.status = "CANCELLED_TIMEOUT"
                self.bus.publish("OrderCancelled", {"order_id": order.order_id, "reason": "timeout"})

    def advance_tick(self, steps=1):
        self.tick += steps

    def reconciliation_report(self):
        issues = []
        for order in self.orders.values():
            reservation = self.inventory.reservations.get(order.order_id)
            if order.status == "PAID" and reservation and reservation.status != "CONFIRMED":
                issues.append(f"paid order {order.order_id} not confirmed in inventory")
            if order.status in {"PAYMENT_FAILED", "CANCELLED_TIMEOUT", "REJECTED"} and reservation and reservation.status == "RESERVED":
                issues.append(f"cancelled/failed order {order.order_id} still has reserved stock")
        return issues


class PaymentService:
    def __init__(self, bus: EventBus):
        self.bus = bus
        self.payments: Dict[str, Payment] = {}

    def create_payment(self, order_id: str, amount: int):
        payment = self.payments.get(order_id)
        if payment:
            return payment
        payment = Payment(order_id=order_id, amount=amount, status="INIT")
        self.payments[order_id] = payment
        return payment

    def callback(self, order_id: str, success: bool, provider_txn_id: str):
        payment = self.payments.setdefault(order_id, Payment(order_id=order_id, amount=0, status="INIT"))
        if payment.status == "SUCCESS":
            return  # idempotent duplicate callback
        if payment.status == "FAILED" and not success:
            return

        payment.provider_txn_id = provider_txn_id
        if success:
            payment.status = "SUCCESS"
            self.bus.publish("PaymentSucceeded", {"order_id": order_id, "provider_txn_id": provider_txn_id})
        else:
            payment.status = "FAILED"
            self.bus.publish("PaymentFailed", {"order_id": order_id, "provider_txn_id": provider_txn_id})


class ShippingService:
    def __init__(self):
        self.shipments: Set[str] = set()

    def create_shipping(self, order_id: str):
        self.shipments.add(order_id)


def main():
    bus = EventBus()
    inventory = InventoryService()
    inventory.add_product("sku-1", 5)

    orders = OrderService(inventory, bus)
    payments = PaymentService(bus)
    shipping = ShippingService()

    # subscriptions
    bus.subscribe("OrderCreated", "payment-create", lambda e: payments.create_payment(e.payload["order_id"], e.payload["amount"]))
    bus.subscribe("PaymentSucceeded", "order-paid", lambda e: orders.mark_paid(e.payload["order_id"]))
    bus.subscribe("PaymentFailed", "order-payfail", lambda e: orders.mark_payment_failed(e.payload["order_id"]))
    bus.subscribe("OrderPaid", "inventory-confirm", lambda e: inventory.confirm(e.payload["order_id"]))
    bus.subscribe("OrderPaid", "shipping-create", lambda e: shipping.create_shipping(e.payload["order_id"]))
    bus.subscribe("OrderCancelled", "inventory-release", lambda e: inventory.release(e.payload["order_id"]))

    # Case 1: successful order
    result1 = orders.create_order("req-1", "user-1", "sku-1", 2, 200)
    bus.drain()
    payments.callback(result1["order_id"], True, "txn-100")
    payments.callback(result1["order_id"], True, "txn-100")  # duplicate callback
    bus.drain()

    # Case 2: payment failure -> release reservation
    result2 = orders.create_order("req-2", "user-2", "sku-1", 2, 200)
    bus.drain()
    payments.callback(result2["order_id"], False, "txn-200")
    bus.drain()

    # Case 3: timeout unpaid order -> release reservation
    result3 = orders.create_order("req-3", "user-3", "sku-1", 1, 100)
    bus.drain()
    orders.advance_tick(steps=4)
    orders.cancel_expired()
    bus.drain()

    # Case 4: idempotent create order request
    result4a = orders.create_order("req-4", "user-4", "sku-1", 1, 100)
    result4b = orders.create_order("req-4", "user-4", "sku-1", 1, 100)
    bus.drain()

    print("=== Order Results ===")
    print("success order:", result1)
    print("payment failed order:", result2)
    print("timeout order:", result3)
    print("idempotent create first:", result4a)
    print("idempotent create second:", result4b)
    print()

    print("=== Final Order States ===")
    for oid, order in orders.orders.items():
        print(oid, order.status)
    print()

    print("=== Inventory Snapshot ===")
    print(inventory.snapshot())
    print()

    print("=== Reservation States ===")
    for oid, reservation in inventory.reservations.items():
        print(oid, reservation.status)
    print()

    print("=== Payment States ===")
    for oid, payment in payments.payments.items():
        print(oid, payment.status, payment.provider_txn_id)
    print()

    print("=== Shipments ===")
    print(sorted(shipping.shipments))
    print()

    print("=== Reconciliation Report ===")
    issues = orders.reconciliation_report()
    if issues:
        for issue in issues:
            print("ISSUE:", issue)
    else:
        print("No inconsistencies detected in simulation.")


if __name__ == "__main__":
    main()
